draw(rightanglemark(Y,X,Z,23));

label("$X$",X,SW);

label("$Y$",Y,SE);

label("$Z$",Z,N);

label("$100$",(Y+Z)/2,NE);

label("$k$",(Z)/2,W);

label("$7k$",Y/2,S);

[/asy]

